import React, { Component } from 'react';
import { withRouter, Link } from 'react-router-dom';
import s from './UploadView.module.scss';
import Dropzone from 'react-dropzone';

function Previews(props) {
    const [files, setFiles] = useState([]);

    const previews = <div>test</div>;

    return (
        {previews}
    )
}

class UploadView extends Component {

    constructor(props) {
        super(props);
        this.state = {
            files: []
        };

        this.handleAttachFile = this.handleAttachFile.bind(this);
    }

    handleAttachFile(e) {
        this.setState({ files: e.target.files });        
    }

    render() {

        return (
            <>
                <Dropzone onDrop={acceptedFiles => console.log(acceptedFiles)}>
                {({getRootProps, getInputProps}) => (
                    // <section>
                        <div {...getRootProps()} className={s.drop}>
                            <input {...getInputProps()} />
                            <p>Przeciągnij tutaj pliki lub kliknij żeby wybrać.</p>
                        </div>
                    // </section>
                )}
                </Dropzone>
                <div className={s.files}>
                    <div className={s.files__item}>
                        <Previews/>
                    </div>
                </div>
            </>
        )
    }
}

export default withRouter(UploadView);
